import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.nio.file.Path;
import java.nio.file.Paths;

public class PathTraversalSecure {
    public static void main(String[] args) {
        String userInput = "../../../etc/passwd";
        String baseDirectory = "/path/to/files/";

        // Validate and sanitize user input to prevent path traversal
        Path resolvedPath = Paths.get(baseDirectory).resolve(Paths.get(userInput)).normalize();

        if (!resolvedPath.startsWith(Paths.get(baseDirectory))) {
            System.err.println("Invalid file path");
            return;
        }

        try (BufferedReader br = new BufferedReader(new FileReader(resolvedPath.toFile()))) {
            String line;
            while ((line = br.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

